# BEST PRACTICE: Hierarchical Pattern with Checkpoints
from enum import Enum
from dataclasses import dataclass

class BatsmanRole(Enum):
    OPENER = "high_risk_boundaries"
    MIDDLE_ORDER = "stability_building"
    FINISHER = "explosive_acceleration"

@dataclass
class CricketInning:
    runs_target: int
    wickets_lost: int = 0
    current_score: int = 0
    strategy_checkpoint: str = "initial"

class CaptainAgent:
    """Hierarchical supervisor for batting strategy"""
    def assign_batsman(self, inning: CricketInning, role: BatsmanRole):
        if inning.runs_target < 50 and inning.wickets_lost < 3:
            return {"role": role, "instruction": "aggressive_batting", "risk_level": 0.8}
        elif inning.runs_target > 100 and inning.wickets_lost > 5:
            return {"role": role, "instruction": "cautious_blocking", "risk_level": 0.2}
        else:
            return {"role": role, "instruction": "balanced_approach", "risk_level": 0.5}

    def checkpoint_decision(self, inning: CricketInning):
        """Critical: Always checkpoint before delegating"""
        inning.strategy_checkpoint = "batsman_assigned"
        return self.assign_batsman(inning, BatsmanRole.OPENER)

